#include <bits/stdc++.h>
using namespace std;
string a,b;
unsigned long long a1,b1;
int ss(char s) {
	return s-64;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>b;
	a1=b1=1;
	for(int i=0; i<a.size(); i++) {
		a1*=ss(a[i]);
		a1%=47;
	}
	for(int i=0; i<b.size(); i++) {
		b1*=ss(b[i]);
		b1%=47;
	}
	(a1==b1?cout<<"GO":cout<<"STAY");
	return 0;
}
